style.css.data:
body > table {
  width: 100%;
  padding: 2em;
}

.logo {
  display: block;
  height: 96px;
}

.header_image_section,
.header_supplied_section,
.body_section,
.body_total_section {
  width: 100%;
}

.header_supplied_section {
  font-family: Tahoma;
  font-size: 8pt;
  border-bottom: 0.5px solid black;
  padding-top: 1pt;
}

.header_image_section {
  width: 100%;
  font-family: Tahoma;
  font-size: 8pt;
  border-bottom: 0.5px solid black;
  padding-top: 8pt;
  font-family: "Gill Sans", "Gill Sans MT", Calibri, "Trebuchet MS", sans-serif;
}

.header-space-between {
  display: flex;
  justify-content: space-between;
}
.body_column_label th {
  border-bottom: 0.5px solid black;
  text-align: left;
}

.body_column_label th,
.body_value td {
  font-family: Tahoma;
  font-size: 8pt;
}

data.query:
query requisitionQuery($storeId: String!, $dataId: String!) {
  requisition(storeId: $storeId, id: $dataId) {
    ... on RequisitionNode {
      id
      status
      requisitionNumber
      theirReference
      createdDatetime
      sentDatetime
      finalisedDatetime
      comment
      maxMonthsOfStock
      otherParty(storeId: $storeId) {
        name
        id
        code
        address1
        address2
        phone
        email
      }
      lines {
        nodes {
          requestedQuantity
          comment
          item {
            code
            name
            unitName
          }
          itemStats {
            availableStockOnHand
            averageMonthlyConsumption
            monthsOfStockOnHand
          }
        }
      }
    }
  }
  store(id: $storeId) {
    ... on StoreNode {
      code
      storeName
      logo
      name(storeId: $storeId) {
        ... on NameNode {
          address1
          address2
          code
          email
          phone
        }
      }
    }
  }
}
